var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`호오. 늙은이 불러다 놓고 잔치라도 벌일 기세군.`,JPN:`ほう、こんな老いぼれを呼び出して、長寿祝いでもしてくれるのか？`,ENG:`Hmm, I'm afraid I might be too old for this sort of party.`,TWN:`哦，把我這老人叫來這裡，看來是要辦什麼派對的樣子呢。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`그래, 종신계약이라고 하던데......`,JPN:`ああ、終身契約とは聞いているが……`,ENG:`So, a lifetime contract, huh?`,TWN:`是嗎，你說是要簽終身契約……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`말을 너무 늦게 꺼냈다는 생각은 안 드나?`,JPN:`切り出すタイミングが遅すぎるのではないか。`,ENG:`Didn't it cross your mind that you were a bit late to ask me this?`,TWN:`你不覺得這話說得太晚了嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`평생을 군에서 보냈어. 여생 정도는 조용히 지내야지.`,JPN:`私は生涯を軍務に費やしてきた。余生ぐらいは静かに過ごさせてほしいものだ。`,ENG:`I've spent my entire life in the Army. I want to spend my retirement someplace quiet.`,TWN:`我這一輩子都是在軍隊裡度過的，餘生也該過得平靜點吧。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`하긴...... 생각해 보면 있지도 않은 손주한테 읽어 줄 책이라고는 전쟁론밖에 없군.`,JPN:`とは言え……いつか私が孫に読み聞かせる本はおそらく戦争論だろう。まあ、孫などいやしないがな。`,ENG:`But then again, I've got nothing but war stories to tell my grandchildren, who don't even exist.`,TWN:`也是……仔細想想，我能給不曾存在的孫子念的故事書，也只有戰爭理論了。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`그래. 기왕 계속해야 될 싸움이라면......`,JPN:`いいだろう。どうせ戦い続けるのなら……`,ENG:`Okay, if I have no choice but to fight...`,TWN:`好吧，既然都要繼續戰鬥的話……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`자네처럼 등을 맡길 수 있는 전우와 손잡는 편이 좋겠지.`,JPN:`君のように背中を預けられる戦友と手を携えるのがよかろう。`,ENG:`I should join forces with someone whom I can trust.`,TWN:`還是和你這種，能夠託付身後的戰友聯手比較好。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};